    execution_id: $execution.id
};

console.log('CONVERSATION_LOG:', JSON.stringify(logEntry));

return $json;

// ============================================
// PREPARAR CONTEXTO PEDIDO v2.0 - DELIVERY
// ============================================
try {
    const filaData = $('Processar Fila').first().json;
    const redisResponse = $json;

    let orderState = null;
    try {
        if (redisResponse && redisResponse.result && redisResponse.result !== null) {
            orderState = JSON.parse(redisResponse.result);
        }
    } catch(e) { orderState = null; }

    if (!orderState) {
        orderState = {
            phase: "idle",
            items: [],
            nome_cliente: null,
            endereco: null,
            complemento: null,
            bairro: null,
            forma_pagamento: null,
            troco_para: null,
            total: 0,
            confirmado: false
        };
    }

    let orderSummary = "";
    if (orderState.phase === "idle") {
        orderSummary = "Nenhum pedido em andamento.";
    } else if (orderState.phase === "coletando") {
        const itensList = orderState.items.length > 0
            ? orderState.items.map(i => `${i.nome} x${i.quantidade}`).join(", ")
            : "nenhum ainda";
        orderSummary = `PEDIDO EM ANDAMENTO (coletando informações):\n` +
            `- Itens: ${itensList}\n` +
            `- Nome: ${orderState.nome_cliente || "não informado"}\n` +
            `- Endereço: ${orderState.endereco || "não informado"}\n` +
            `- Complemento: ${orderState.complemento || "não informado"}\n` +
            `- Bairro: ${orderState.bairro || "não informado"}\n` +
            `- Pagamento: ${orderState.forma_pagamento || "não informado"}\n` +
            `- Troco: ${orderState.troco_para ? "R$ " + orderState.troco_para : "não necessário"}\n` +
            `- Total parcial: R$ ${orderState.total}`;
    } else if (orderState.phase === "aguardando_confirmacao") {
        const itensList = orderState.items
            .map(i => `  • ${i.nome} x${i.quantidade} — R$ ${i.preco_total}`)
            .join("\n");
        orderSummary = `PEDIDO AGUARDANDO CONFIRMAÇÃO DO CLIENTE:\n` +
            `${itensList}\n` +
            `- Nome: ${orderState.nome_cliente}\n` +
            `- Endereço: ${orderState.endereco}${orderState.complemento ? ", " + orderState.complemento : ""} — ${orderState.bairro}\n` +
            `- Pagamento: ${orderState.forma_pagamento}\n` +
            `${orderState.troco_para ? "- Troco para: R$ " + orderState.troco_para + "\n" : ""}` +
            `- TOTAL: R$ ${orderState.total}`;
    } else if (orderState.phase === "finalizado") {
        orderSummary = "Pedido finalizado e confirmado pelo cliente.";
    }

    return [{
        json: {
            ...filaData,
            order_state: JSON.stringify(orderState),
            order_summary: orderSummary,
            order_phase: orderState.phase
        }
    }];

} catch (error) {
    console.error("Preparar Contexto Pedido: Erro -", error.message);
    const filaData = $('Processar Fila').first().json;
    return [{
        json: {
            ...filaData,
            order_state: '{"phase":"idle","items":[],"nome_cliente":null,"endereco":null,"complemento":null,"bairro":null,"forma_pagamento":null,"troco_para":null,"total":0,"confirmado":false}',
            order_summary: "Nenhum pedido em andamento.",
            order_phase: "idle"
        }
    }];
}

// ============================================
// PREPARAR SALVAR PEDIDO v1.1 - CORRIGIDO
// ============================================
try {
    const responseData = $json;

    if (responseData.new_order_state) {
        const clientId = responseData.client_id;
        const stateStr = typeof responseData.new_order_state === 'string'
            ? responseData.new_order_state
            : JSON.stringify(responseData.new_order_state);

        return {
            ...responseData,
            redis_key: `pedido_state:${clientId}`,
            redis_value: stateStr,
            redis_ttl: 7200
        };
    }

    return {
        ...responseData,
        redis_key: `pedido_noop`,
        redis_value: '{}',
        redis_ttl: 7200
    };
} catch(error) {
    console.error('Preparar Salvar Pedido: Erro -', error.message);
    return $json;
}

// ============================================
