// ============================================
const key = $json.redis_key || 'pedido_noop';
const value = encodeURIComponent($json.redis_value || '{}');
const ttl = $json.redis_ttl || 7200;

try {
    await this.helpers.httpRequest({
        method: 'POST',
        url: `https://peaceful-sailfish-14074.upstash.io/set/${key}/${value}/EX/${ttl}`,
        headers: {
            'Authorization': 'Bearer ATb6AAIncDFkNzcxNmI2MjYwMzc0OWIyYTE4Yzk1YjA4NjZkZDk2ZXAxMTQwNzQ'
        }
    });
} catch(e) {
    console.error('Redis save error:', e.message);
}

return [{
    json: {
        client_id: $json.client_id,
        client_name: $json.client_name,
        response_text: $json.response_text,
        escalate_human: $json.escalate_human,
        intent: $json.intent,
        confidence: $json.confidence,
        session_id: $json.session_id,
        timestamp: $json.timestamp,
        wait_seconds: $json.wait_seconds,
        new_order_state: $json.new_order_state
    }
}];

const order = JSON.parse($('Processar Resposta').first().json.new_order_state);

const itens = order.items.map(i => {
  let linha = '• ' + i.nome + ' x' + i.quantidade + ' — R$ ' + i.preco_total.toFixed(2);
  if (i.detalhes?.sabores?.length)      linha += '\n  Sabores: ' + i.detalhes.sabores.join(', ');
  if (i.detalhes?.complementos?.length) linha += '\n  Complementos: ' + i.detalhes.complementos.join(', ');
  if (i.detalhes?.acompanhamento)       linha += '\n  Acompanhamento: ' + i.detalhes.acompanhamento;
  if (i.detalhes?.cobertura)            linha += '\n  Cobertura: ' + i.detalhes.cobertura;
  if (i.detalhes?.fruta)                linha += '\n  Fruta: ' + i.detalhes.fruta;
  return linha;
}).join('\n');

const entrega = order.bairro
  ? 'Delivery\n📍 ' + order.endereco + ', ' + order.bairro + (order.complemento ? ' — ' + order.complemento : '')
  : 'Retirada no balcão';

const taxa = order.taxa_entrega
  ? '*Taxa:* R$ ' + parseFloat(order.taxa_entrega).toFixed(2) + '\n'
  : '';

const pagamento = '*Pagamento:* ' + (order.forma_pagamento || '-') + '\n' +
  (order.troco_para ? '*Troco para:* R$ ' + order.troco_para + '\n' : '');

const adminMessage =
  '🛎️ *NOVO PEDIDO CONFIRMADO*\n\n' +
  '👤 *Cliente:* ' + $('Processar Resposta').first().json.client_name + '\n' +
  '📱 *Telefone:* ' + $('Processar Resposta').first().json.client_id + '\n\n' +
  '*Itens:*\n' + itens + '\n\n' +
  '*Entrega:* ' + entrega + '\n' +
  taxa +
  pagamento +
  '\n*Total: R$ ' + order.total.toFixed(2) + '*';

return {
  json: {
    ...$('Processar Resposta').first().json,
    admin_message: adminMessage
  }
